rule.example:
fun process(items: List<Int>, threshold: Int): Int {
    var result = 0
    for (item in items) {              // +1 (nesting 0)
        if (item > threshold) {        // +2 (nesting 1)
            if (item % 2 == 0) {       // +3 (nesting 2)
                result += item
            }
        }
    }
    return result
}
// cognitive complexity = 6 (1 + 2 + 3)

rule.description:
Reports nested `if` statements that can be merged together by joining their
conditions with a boolean `&&` operator.

Only flags the inner `if` when it is the sole statement of the outer `if`'s body
and neither has an `else` branch. For example:

```kotlin
if (x) {
    if (y) { ... }     // violation: merge to: if (x && y) { ... }
}
```

Kotlin equivalent of Java rule: category/java/design.xml/CollapsibleIfStatements

rule.example:
class Foo {
    fun bar(x: Boolean, y: Boolean) {
        if (x) {            // violation: can be merged
            if (y) {
                println("both")
            }
        }
        if (x) {            // ok: outer has else
            if (y) { println("both") }
        } else {
            println("neither")
        }
        if (x && y) {       // ok: already merged
            println("both")
        }
    }
}

fun describe(n: Int): String = when {
    n < 0   -> "negative"   // +1
    n == 0  -> "zero"       // +1
    n < 10  -> "small"      // +1
    n < 100 -> "medium"     // +1
    n < 1000 -> "large"     // +1
    else    -> "huge"
}
// complexity = 6 (base 1 + 5 branches)

// violation: too many parameters
fun createRecord(a: Int, b: Int, c: Int, d: Int, e: Int,
                 f: Int, g: Int, h: Int, i: Int, j: Int, k: Int) { }

// ok: wrap related parameters in a data class
data class RecordParams(val a: Int, val b: Int, val c: Int)
fun createRecord(params: RecordParams) { }

property.value:
(: x && true, true && x :)
//Conjunction[T-CONJ and Equality[pmd-kotlin:nodeText() = 'true']]
|
(: x || false, false || x :)
//Disjunction[T-DISJ and Conjunction[pmd-kotlin:nodeText() = 'false']]

rule.example:
class Bar {
    val isFoo: Boolean = false

    fun check(): Boolean {
        val a = isFoo && true      // violation: use isFoo directly
        val b = isFoo || false     // violation: use isFoo directly
        val c = isFoo              // ok
        val d = isFoo == true      // ok: idiomatic nullable Boolean check
        return a && b && c && d
    }
}

rule.description:
Avoid unnecessary `if`/`else` or `when` expressions when both branches yield a bare
boolean literal. The condition itself (or its negation) can be used directly in any
context: return, assignment, expression body, or function argument.

```kotlin
// violation -- return form:
if (bar == x) return true else return false
// simplify to:
return bar == x

// violation -- expression/assignment form (Kotlin-specific):
fun isEqual(bar: Int, x: Int) = if (bar == x) true else false
val result = if (bar == x) true else false
// simplify to:
fun isEqual(bar: Int, x: Int) = bar == x
val result = bar == x

// violation -- when form (Kotlin-specific):
val result = when { bar == x -> true; else -> false }
// simplify to:
val result = bar == x
```

Kotlin equivalent of Java rule: category/java/design.xml/SimplifyBooleanReturns

