rule.example:
class Foo {
    // violation -- return form: replace with return bar == x
    fun isBarEqualTo(bar: Int, x: Int): Boolean {
        if (bar == x) {
            return true
        } else {
            return false
        }
    }

    // violation -- expression body: replace with fun isBarSame(bar: Int, x: Int) = bar == x
    fun isBarSame(bar: Int, x: Int): Boolean = if (bar == x) true else false

    // violation -- assignment: replace with val result = bar == x
    fun compute(bar: Int, x: Int): Boolean {
        val result = if (bar == x) true else false
        return result
    }

    // violation -- when form: replace with return bar == x
    fun isBarSameWhen(bar: Int, x: Int): Boolean = when {
        bar == x -> true
        else -> false
    }

    fun isBarGreaterThan(bar: Int, x: Int): Boolean {
        return bar > x      // ok: already a direct boolean expression
    }
}
